#include <cmath>
double ep_azimuth_diff(double azm_a, double azm_b) {
    double diff = azm_b - azm_a;
    if (diff > 180.0)       diff = 360.0 - diff;
    else if (diff < -180.0) diff = 360.0 + diff;
    return std::abs(diff);
}

